   227→func QueryData(ctx context.Context, log log.Logger, dscache datasources.CacheService, exprService *expr.Service, reqDTO dtos.MetricRequest, qsDatasourceClientBuilder dsquerierclient.QSDatasourceClientBuilder, headers map[string]string) (*backend.QueryDataResponse, error) {
   228→	s := &ServiceImpl{
   229→		log:                        log,
   230→		dataSourceCache:            dscache,
   231→		expressionService:          exprService,
   232→		dataSourceRequestValidator: validations.ProvideValidator(),
   233→		qsDatasourceClientBuilder:  qsDatasourceClientBuilder,
   234→		headers:                    headers,
   235→		concurrentQueryLimit:       16, // TODO: make it configurable
   236→	}
   237→
   238→	user, err := identity.GetRequester(ctx)
   239→	if err != nil {
   240→		return nil, err
   241→	}
   242→
   243→	return s.QueryDataNew(ctx, user, false, reqDTO)
   244→}
   245→
   246→// handleExpressions handles queries when there is an expression.
   247→func (s *ServiceImpl) handleExpressions(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
   248→	exprReq := expr.Request{
   249→		Queries: []expr.Query{},
   250→	}
   251→
   252→	if user != nil { // for passthrough authentication, SSE does not authenticate
   253→		exprReq.User = user
   254→		exprReq.OrgId = user.GetOrgID()
   255→	}
   256→
   257→	for _, pq := range parsedReq.getFlattenedQueries() {
   258→		if pq.datasource == nil {
   259→			return nil, ErrMissingDataSourceInfo.Build(errutil.TemplateData{
   260→				Public: map[string]any{
   261→					"RefId": pq.query.RefID,
   262→				},
   263→			})
   264→		}
   265→
   266→		exprReq.Queries = append(exprReq.Queries, expr.Query{
   267→			JSON:          pq.query.JSON,
   268→			Interval:      pq.query.Interval,
   269→			RefID:         pq.query.RefID,
   270→			MaxDataPoints: pq.query.MaxDataPoints,
   271→			QueryType:     pq.query.QueryType,
   272→			DataSource:    pq.datasource,
   273→			TimeRange: expr.AbsoluteTimeRange{
   274→				From: pq.query.TimeRange.From,
   275→				To:   pq.query.TimeRange.To,
   276→			},
   277→		})
   278→	}
   279→
   280→	qdr, err := s.expressionService.TransformData(ctx, time.Now(), &exprReq) // use time now because all queries have absolute time range
   281→	if err != nil {
   282→		return nil, fmt.Errorf("expression request error: %w", err)
   283→	}
   284→	return qdr, nil
   285→}
   286→
   287→// handleQuerySingleDatasource handles one or more queries to a single datasource
   288→func (s *ServiceImpl) handleQuerySingleDatasource(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
   289→	queries := parsedReq.getFlattenedQueries()
   290→	ds := queries[0].datasource
   291→	if err := s.dataSourceRequestValidator.Validate(ds, nil); err != nil {
   292→		return nil, datasources.ErrDataSourceAccessDenied
   293→	}
   294→
   295→	// ensure that each query passed to this function has the same datasource
   296→	for _, pq := range queries {
   297→		if ds.UID != pq.datasource.UID {
   298→			return nil, fmt.Errorf("all queries must have the same datasource - found %s and %s", ds.UID, pq.datasource.UID)
   299→		}
   300→	}
   301→
   302→	req := &backend.QueryDataRequest{
   303→		Headers: map[string]string{},
   304→		Queries: []backend.DataQuery{},
   305→	}
   306→
   307→	for _, q := range queries {
   308→		req.Queries = append(req.Queries, q.query)
   309→	}
   310→
   311→	qsDsClient, ok, err := s.qsDatasourceClientBuilder.BuildClient(ds.Type, ds.UID)
   312→	if err != nil {
   313→		return nil, err
   314→	}
   315→
   316→	if !ok { // single tenant flow
   317→		pCtx, err := s.pCtxProvider.GetWithDataSource(ctx, ds.Type, user, ds)
   318→		if err != nil {
   319→			return nil, err
   320→		}
   321→		req.PluginContext = pCtx
   322→		return s.pluginClient.QueryData(ctx, req)
   323→	} else { // query-service flow (single or multi tenant)
   324→		// transform request from backend.QueryDataRequest to k8s request
   325→		k8sReq, err := expr.ConvertBackendRequestToDataRequest(req)
   326→		if err != nil {
   327→			return nil, err
   328→		}
   329→		return qsDsClient.QueryData(ctx, *k8sReq)
   330→	}
   331→}
   332→
   333→func getTimeRange(query *simplejson.Json, globalFrom string, globalTo string) (string, string, error) {
   334→	tr, ok := query.CheckGet("timeRange")
   335→	if !ok { // timeRange json node does not exist, use global from/to
   336→		return globalFrom, globalTo, nil
   337→	}
   338→	from, err := tr.Get("from").String()
   339→	if err != nil {
   340→		return "", "", errors.New("time range: field 'from' is missing or invalid")
   341→	}
   342→	to, err := tr.Get("to").String()
   343→	if err != nil {
